/// <summary>Provides a valid sample JPEG for <c>--mock</c> mode, so the full pipeline
/// (browser → agent → cloud upload) can be tested without a physical scanner.</summary>
internal static class Mock
{
    // A valid baseline JPEG (1×1 placeholder "scanned page"). Kept as a single literal so it stays valid base64.
    private const string SampleBase64 =
        "";

    public static byte[] SampleJpeg() => Convert.FromBase64String(SampleBase64);
}
